import json
import boto3
import os
from datetime import datetime

# Initialize AWS clients (outside handler for connection reuse)
s3_client = boto3.client('s3')
dynamodb = boto3.resource('dynamodb')

# Environment variables
METADATA_TABLE = os.environ.get('METADATA_TABLE', 'upload-metadata')

def lambda_handler(event, context):
    """
    AWS Lambda function handler for processing S3 upload events.
    This function is triggered when new files are uploaded to S3.

    Args:
        event: S3 event containing bucket name and file key
        context: Lambda runtime context

    Returns:
        dict: HTTP response with status code and body
    """
    print(f"Received event: {json.dumps(event)}")

    try:
        # Extract bucket name and object key from event
        for record in event.get('Records', []):
            bucket_name = record['s3']['bucket']['name']
            object_key = record['s3']['object']['key']

            print(f"Processing file: {object_key} from bucket: {bucket_name}")

            # Get file metadata
            response = s3_client.head_object(Bucket=bucket_name, Key=object_key)
            file_size = response['ContentLength']
            content_type = response.get('ContentType', 'unknown')

            # Process based on file type
            if object_key.lower().endswith(('.jpg', '.jpeg', '.png')):
                result = process_image(bucket_name, object_key, file_size)
            elif object_key.lower().endswith('.pdf'):
                result = process_document(bucket_name, object_key, file_size)
            else:
                result = process_generic_file(bucket_name, object_key, file_size)

            # Store metadata in DynamoDB
            store_metadata(bucket_name, object_key, file_size, content_type, result)

        return {
            'statusCode': 200,
            'body': json.dumps({
                'message': 'Files processed successfully',
                'processed_count': len(event.get('Records', []))
            })
        }

    except Exception as e:
        print(f"Error processing event: {str(e)}")
        return {
            'statusCode': 500,
            'body': json.dumps({'error': str(e)})
        }

def process_image(bucket: str, key: str, size: int) -> dict:
    """Process uploaded image file - example image processing logic"""
    print(f"Processing image: {key} (size: {size} bytes)")
    return {
        'type': 'image',
        'processed': True,
        'thumbnail_generated': True
    }

def process_document(bucket: str, key: str, size: int) -> dict:
    """Process uploaded PDF/document file"""
    print(f"Processing document: {key} (size: {size} bytes)")
    return {
        'type': 'document',
        'processed': True,
        'text_extracted': True
    }

def process_generic_file(bucket: str, key: str, size: int) -> dict:
    """Process generic file upload"""
    print(f"Processing generic file: {key} (size: {size} bytes)")
    return {
        'type': 'generic',
        'processed': True
    }

def store_metadata(bucket: str, key: str, size: int, content_type: str, result: dict):
    """Store file metadata in DynamoDB for tracking"""
    table = dynamodb.Table(METADATA_TABLE)

    item = {
        'file_key': key,
        'bucket': bucket,
        'size_bytes': size,
        'content_type': content_type,
        'processed': result.get('processed', False),
        'upload_timestamp': datetime.utcnow().isoformat()
    }

    table.put_item(Item=item)
    print(f"Metadata stored for: {key}")

# Example invocation (for testing)
if __name__ == "__main__":
    # Sample S3 event
    test_event = {
        'Records': [{
            's3': {
                'bucket': {'name': 'my-upload-bucket'},
                'object': {'key': 'sample-image.jpg'}
            }
        }]
    }
    test_context = type('Context', (), {'function_name': 'ImageProcessor', 'memory_limit_in_mb': 128})()

    print(lambda_handler(test_event, test_context))
